const GUANYIN_100_DATA = [
{no:1,displayNo:"第1籤",level:"上籤",title:"觀音第1籤",poem:["天開地闢結良緣","日吉時良萬事全","若得此籤非小可","人行中正帝王宣"],story:"觀音第1首",classicMeaning:"急速兆速。年未值時。觀音降筆。先報君知。",plainMeaning:"此卦盤古初開天地之象。諸事皆吉也。",categoryReadings:{總論:"急速兆速。年未值時。觀音降筆。先報君知。",聖意:"家宅　祈福。自身　秋冬大利。求財　秋冬大利。交易　成。婚姻　成。六甲　生男。行人　至。田蠶　好。六畜　好。尋人　見。公訟　吉。移徙　失物　東北。疾病　設送。山墳　吉。"},actionAdvice:["把握秋冬時機積極行動，貴人相助，諸事順遂，特別在求財與事業方面大有可為。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:2,displayNo:"第2籤",level:"上籤",title:"觀音第2籤",poem:["鯨魚未化守江湖","未許升騰離碧波","異日崢嶸身變態","從教一躍禹門過"],story:"觀音第2首",classicMeaning:"得忍且忍。得耐且耐。須待時至。功名還在。",plainMeaning:"此卦鯨魚未變之象。凡事忍耐待時也。",categoryReadings:{總論:"得忍且忍。得耐且耐。須待時至。功名還在。",聖意:"家宅　不安。自身　還願。求財　欠利。交易　婚姻　難。六甲　作福。行人　平安。田蠶　吉。六畜　不利。尋人　見。公訟　和。移徙　去。失物　東南。疾病　祈保。山墳　吉。"},actionAdvice:["目前運勢未至，宜耐心等待時機，切勿急躁冒進，守舊為上策。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:3,displayNo:"第3籤",level:"上籤",title:"觀音第3籤",poem:["衝風冒雨去還歸","役役勞身似燕兒","啣得泥來成疊後","到頭疊壞復成泥"],story:"觀音第3首",classicMeaning:"千般用計。晨昏不停。誰知此事。到底勞心。",plainMeaning:"此卦燕子啣坭之象。凡事勞心費力也。",categoryReadings:{總論:"千般用計。晨昏不停。誰知此事。到底勞心。",聖意:"家宅　先凶后吉。自身　謹防。求財　有。交易　成。婚姻　不合。六甲　男。行人　吉。田蠶　利。六畜　利。尋人　見。公訟　有理。移徙　安。失物　見。疾病　還願。山墳　吉。"},actionAdvice:["雖然勞心費力，但堅持到底會有收穫，注意婚姻方面可能不順，需多加謹慎。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:4,displayNo:"第4籤",level:"上籤",title:"觀音第4籤",poem:["菱花鏡破復重圓","女再求夫男再婚","自此門閭重改換","更添福祿與兒孫"],story:"觀音第4首",classicMeaning:"淘沙成金。騎龍踏虎。雖是勞心。于中有補。",plainMeaning:"此卦串鏡重圓之象。凡事勞心有貴也。",categoryReadings:{總論:"淘沙成金。騎龍踏虎。雖是勞心。于中有補。",聖意:"家宅　欠利。自身　秋冬旺。求財　秋冬旺。交易　允。婚姻　成。六甲　祈保。行人　至。田蠶　可養。六畜　可養。尋人　見。公訟　不利。移徙　守舊。失物　遲見。疾病　祈福。山墳　吉。"},actionAdvice:["淘沙成金終有回報，秋冬時節運勢最旺，婚姻可成，但須防訴訟糾紛。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:5,displayNo:"第5籤",level:"上籤",title:"觀音第5籤",poem:["一鋤掘地要求泉","努力求之得最先","無意俄然遇知己","相逢攜手上青天"],story:"觀音第5首",classicMeaning:"欲望心事。西方可求。不如莫動。立地可謀。",plainMeaning:"此卦錐地求泉之象。凡事先難后易也。",categoryReadings:{總論:"欲望心事。西方可求。不如莫動。立地可謀。",聖意:"家宅　祈福。自身　利。求財　利。交易　合。婚姻　合。六甲　安。行人　遲。田蠶　宜早種。六畜　損。尋人　見。公訟　宜和。移徙　吉。失物　不見。疾病　禳星。山墳　吉。"},actionAdvice:["積極向西方尋求機會，莫要猶豫等待，凡事先難後易，終有貴人相助成就事業。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:6,displayNo:"第6籤",level:"上籤",title:"觀音第6籤",poem:["投身巖下飼於菟","須是還他大丈夫","捨己也應難再得","通行天下此人無"],story:"觀音第6首",classicMeaning:"食用無魚。身清喜貧。待時利樂。權與概人。",plainMeaning:"此卦投岩銅鳥之象。凡事宜順吉之兆。",categoryReadings:{總論:"食用無魚。身清喜貧。待時利樂。權與概人。",聖意:"家宅　不利。自身　中吉。求財　中吉。交易　難。婚姻　平平。六甲　安。行人　近。田蠶　早種。六畜　損。尋人　見。公訟　有理。移徙　吉。失物　見。疾病　設送。山墳　安。"},actionAdvice:["安於現狀，待時利樂，雖生活清貧但內心自在，凡事順其自然則吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:7,displayNo:"第7籤",level:"上籤",title:"觀音第7籤",poem:["奔波役役重重險","帶水拖泥又渡山","更慮他方求別用","千山萬水未能還"],story:"觀音第7首",classicMeaning:"退身可得。進步為難。只宜守舊。莫望高攀。",plainMeaning:"此卦拖泥帶水之象。凡事守舊則吉也。",categoryReadings:{總論:"退身可得。進步為難。只宜守舊。莫望高攀。",聖意:"家宅　不利。自身　祈福。求財　秋冬吉。交易　平平。婚姻　祈福。六甲　祈福。行人　阻。田蠶　不利。六畜　不利。尋人　難。公訟　虧。移徙　吉。失物　不見。疾病　作福。山墳　不利。"},actionAdvice:["退守為上，莫望高攀，凡事守舊則吉，秋冬求財較為順利。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:8,displayNo:"第8籤",level:"上籤",title:"觀音第8籤",poem:["歲寒松柏古栽培","雨雪風霜總不摧","異日必當成大用","功名作個棟樑材"],story:"觀音第8首",classicMeaning:"路上亨通。終身有功。田蠶豐熟。家道興隆。",plainMeaning:"此卦此卦松柏茂林之象。凡事有貴氣也。",categoryReadings:{總論:"路上亨通。終身有功。田蠶豐熟。家道興隆。",聖意:"家宅　吉。自身　順利。求財　中平。交易　旺。婚姻　成。六甲　男。行人　有信。田蠶　利。六畜　損。尋人　至。公訟　有理。移徙　吉。失物　見。疾病　安。山墳　吉。"},actionAdvice:["如松柏經霜不摧，堅持正道終成大器，家業興隆，諸事亨通。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:9,displayNo:"第9籤",level:"上籤",title:"觀音第9籤",poem:["勞苦問我心中事","此意偏宜說向公","一片靈臺明似鏡","恰如明月正當空"],story:"觀音第9首",classicMeaning:"心中正直。理順法寬。聖無私語。終有分明。",plainMeaning:"此卦皎月當空之象。凡事光明通氣也。",categoryReadings:{總論:"心中正直。理順法寬。聖無私語。終有分明。",聖意:"家宅　吉。自身　順。求財　中平。交易　旺。婚姻　成。六甲　男。行人　動。田蠶　利。六畜　損。尋人　至。公訟　有理。移徙　吉。失物　祈福。疾病　安。山墳　吉。"},actionAdvice:["心正則事明，處事公正無私，前途光明通達，凡事自有分明。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:10,displayNo:"第10籤",level:"上籤",title:"觀音第10籤",poem:["櫝藏無價寶和珍","只管他鄉外處尋","好似將燈來覔火","不如安靜莫勞心"],story:"觀音第10首",classicMeaning:"姻緣會遇。何事不成。須無限意。眼前是真。",plainMeaning:"此卦持燈覓火之象。凡事待時成就也。",categoryReadings:{總論:"姻緣會遇。何事不成。須無限意。眼前是真。",聖意:"家宅　欠利。自身　安。求財　難。交易　難。婚姻　合。六甲　女。行人　動。田蠶　秋吉。六畜　難養。尋人　見。公訟　虧。移徙　舊安。失物　難見。疾病　設送。山墳　中平。"},actionAdvice:["寶物就在身邊，莫向他處苦尋，安靜等待時機，姻緣自來相會。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:11,displayNo:"第11籤",level:"上籤",title:"觀音第11籤",poem:["欲求好事喜非常","爭相姻親只暫忙","畢竟到頭成好事","貴人接引貴人鄉"],story:"觀音第11首",classicMeaning:"有意興變。到底安然。若問用事。只近貴人。",plainMeaning:"此卦因禍得福之象。凡事營謀吉利也。",categoryReadings:{總論:"有意興變。到底安然。若問用事。只近貴人。",聖意:"家宅　大吉。自身　順利。求財　有。交易　成。婚姻　合。六甲　男。行人　未至。田蠶　中平。六畜　中平。尋人　見。公訟　有理。移徙　旺。失物　東方。疾病　禳星。山墳　吉。"},actionAdvice:["積極接近貴人，凡事營謀皆吉利，家宅大吉，婚姻和合，諸事順遂。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:12,displayNo:"第12籤",level:"上籤",title:"觀音第12籤",poem:["時臨否極泰當來","抖擻從君出暗埃","若欲卯寅佳信至","管教立志事和諧"],story:"觀音第12首",classicMeaning:"換麻得絲。擊人雙足。要見分明。因災得福。",plainMeaning:"此卦禍中有福之象。凡事先凶後吉也。",categoryReadings:{總論:"換麻得絲。擊人雙足。要見分明。因災得福。",聖意:"家宅　安。自身　吉。求財　有。交易　宜遲。婚姻　成。六甲　男。行人　未回。田蠶　利。六畜　慎吉。尋人　有信。公訟　吉。移徙　守舊。失物　見。疾病　秋吉。山墳　吉。"},actionAdvice:["否極泰來，因災得福，春天到來時運勢明顯好轉，凡事先凶後吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:13,displayNo:"第13籤",level:"上籤",title:"觀音第13籤",poem:["自小生身富貴家","眼前萬事總奢華","要君賜受金魚袋","四海傳名足可誇"],story:"觀音第13首",classicMeaning:"囚人逢赦。病即安然。龍門得遇。名遍名都。",plainMeaning:"此卦龍門得通之象。凡事有變大吉也。",categoryReadings:{總論:"囚人逢赦。病即安然。龍門得遇。名遍名都。",聖意:"家宅　祈福。自身　祈福。求財　秋冬吉。交易　宜遲。婚姻　合。六甲　女。行人　祈保。田蠶　中平。六畜　中平。尋人　見。公訟　有理。移徙　守舊。失物　東方。疾病　安。山墳　吉。"},actionAdvice:["困境即將解除，龍門得通，秋冬時節特別順利，名聲遠播，婚姻可成。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:14,displayNo:"第14籤",level:"上籤",title:"觀音第14籤",poem:["宛如仙鶴出樊籠","脫却羈縻處處通","南北東西無障碍","任君直上九霄中"],story:"觀音第14首",classicMeaning:"任意無虞。路有亨通。隨心自在。逍遙如人。",plainMeaning:"此卦仙鶴離籠之象。凡事先凶後吉也。",categoryReadings:{總論:"任意無虞。路有亨通。隨心自在。逍遙如人。",聖意:"家宅　不安。自身　還願。求財　合。交易　合。婚姻　合。六甲　男。行人　見。田蠶　秋利。六畜　損。尋人　阻。公訟　宜和。移徙　吉。失物　東南。疾病　設送。山墳　吉。"},actionAdvice:["擺脫束縛，處處亨通，隨心自在逍遙，求財交易皆合，但須記得還願。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:15,displayNo:"第15籤",level:"上籤",title:"觀音第15籤",poem:["觸人口氣最難吞","忽有災危禍到門","卵破巢空無宿處","深為穩便把心存"],story:"觀音第15首",classicMeaning:"若人得怨。何時可伸。好言不信。守舊待時。",plainMeaning:"此卦鳥鵲離林之象。凡事到底應心也。",categoryReadings:{總論:"若人得怨。何時可伸。好言不信。守舊待時。",聖意:"家宅　先凶後吉。自身　謹防。求財　吉。交易　成。婚姻　阻滯。六甲　男。行人　順。田蠶　利。六畜　旺。尋人　見。公訟　有理。移徙　難（遠可）。失物　難見。疾病　還願。山墳　吉。"},actionAdvice:["遇怨難伸，好言不信，目前宜守舊待時，凡事謹慎為上。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:16,displayNo:"第16籤",level:"上籤",title:"觀音第16籤",poem:["攢眉思慮暫時開","咫尺雲開見日來","宛如汙泥中片玉","良工一舉出塵埃"],story:"觀音第16首",classicMeaning:"得處無失。損中有益。小人逢凶。君子順吉。",plainMeaning:"此卦陰陽和合之象。凡所謀皆吉也。",categoryReadings:{總論:"得處無失。損中有益。小人逢凶。君子順吉。",聖意:"家宅　不利（漸安）。自身　秋冬吉。求財　成。交易　成。婚姻　成。六甲　虛驚（有寶）。行人　至。田蠶　祈福。六畜　平。尋人　見。公訟　不利。移徙　守舊。失物　阻。疾病　作福。山墳　安。"},actionAdvice:["困境將過，雲開見日，秋冬時節吉利，小人逢凶，君子順吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:17,displayNo:"第17籤",level:"上籤",title:"觀音第17籤",poem:["莫聽閑言與是非","晨昏只好念阿彌","若將妄語為真實","畫餅如何療得飢"],story:"觀音第17首",classicMeaning:"田園價貫好商量。事到公庭彼此傷。縱使機關圖得勝。定為後世子孫殃。",plainMeaning:"此籤切須依本分。自有前程。如有機關。反成害己利人。",categoryReadings:{總論:"田園價貫好商量。事到公庭彼此傷。縱使機關圖得勝。定為後世子孫殃。",聖意:"事悖理。訟必傷。名利未。亦如常。行人阻。病宜禳。且謹慎。保安康。"},actionAdvice:["莫聽閒言是非，安守本分，保持正直，凡事謹慎方可保安康。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:18,displayNo:"第18籤",level:"上籤",title:"觀音第18籤",poem:["金烏西墜兔東臨","日夜循環恒古今","僧道得之無不利","工商農士各開心"],story:"觀音第18首",classicMeaning:"心中無事。所作有功。如弓上箭。一發當空。",plainMeaning:"此卦陰陽消長之象。凡事遂意之兆也。",categoryReadings:{總論:"心中無事。所作有功。如弓上箭。一發當空。",聖意:"家宅　安。自身　吉。求財　順。交易　成。婚姻　合。六甲　男。行人　至。田蠶　早種。六畜　欠利。尋人　至。公訟　有理。移徙　吉。失物　遲見。疾病　拜送。山墳　大吉。"},actionAdvice:["心中坦蕩無所牽掛，做事必有功，如弓上箭一發當空，諸事順遂。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:19,displayNo:"第19籤",level:"上籤",title:"觀音第19籤",poem:["急水灘頭放艇時","狂風作浪欲何為","待他浪靜風停後","穩載船歸過不危"],story:"觀音第19首",classicMeaning:"急水下船。險處待時。若問營謀。盡可施為。",plainMeaning:"此卦船行急灘之象。凡事守舊待時也。",categoryReadings:{總論:"急水下船。險處待時。若問營謀。盡可施為。",聖意:"家宅　作福。自身　作福。求財　未成。交易　未成。婚姻　不就。六甲　虛驚。行人　至。田蠶　吉。尋人　難。公訟　和（勿興）。移徙　守舊。失物　難尋。疾病　祈福。山墳　吉。"},actionAdvice:["急流中宜守舊待時，切勿冒險妄動，待浪靜風平後再行動為上策。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:20,displayNo:"第20籤",level:"上籤",title:"觀音第20籤",poem:["當春久雨喜初晴","玉兔金烏漸漸明","舊事已成新事遂","看看一跳入蓬瀛"],story:"觀音第20首",classicMeaning:"神佛護持。有災無危。途生平安。到底榮歸。",plainMeaning:"此卦久雨初明之象。凡事遂意也。",categoryReadings:{總論:"神佛護持。有災無危。途生平安。到底榮歸。",聖意:"家宅　中平。自身　祈福。求財　未遇。交易　待時。婚姻　隨意。六甲　女。行人　阻。田蠶　阻。六畜　阻。尋人　遲。公訟　和。移徙　吉。失物　見。疾病　禳星。山墳　吉。"},actionAdvice:["神佛護持，有災無危，求財交易尚需等待時機，凡事耐心終有好結果。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:21,displayNo:"第21籤",level:"上籤",title:"觀音第21籤",poem:["陰陽道合總由天","女嫁男婚豈偶然","但看龍蛇堪運動","熊羆叶夢喜團圓"],story:"觀音第21首",classicMeaning:"謀望從心。婚姻孕男。資財進益。更利田蠶。",plainMeaning:"此卦陰陽道合之象。凡事和大吉也。",categoryReadings:{總論:"謀望從心。婚姻孕男。資財進益。更利田蠶。",聖意:"家宅　安。自身　利。求財　有。交易　成。婚姻　合。六甲　男。行人　至。田蠶　興。六畜　興。尋人　見。公訟　有理。移徙　昌盛。失物　得見。疾病　遇良方。山墳　大吉。"},actionAdvice:["天定良緣，謀望從心，婚姻和合，資財進益，田蠶興旺，諸事大吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:22,displayNo:"第22籤",level:"上籤",title:"觀音第22籤",poem:["四郊田畝皆枯竭","久旱俄然三日霖","花果草芽俱潤澤","始知一雨值千金"],story:"觀音第22首",classicMeaning:"田蠶倍熟。命運漸來。病遇良藥。行人不便。",plainMeaning:"此卦旱逢甘雨之象。凡事難中有救也",categoryReadings:{總論:"田蠶倍熟。命運漸來。病遇良藥。行人不便。",聖意:"家宅　祈保。自身　安。求財　頗有。交易　遲。婚姻　合。六甲　女。行人　有阻。田蠶　利。六畜　利。尋人　難。公訟　虧。移徙　守舊。失物　西方。疾病　設送（必癒）。山墳　安吉。"},actionAdvice:["久旱逢甘霖，難中有救，凡事先難後易，病遇良藥，貴人相助。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:23,displayNo:"第23籤",level:"上籤",title:"觀音第23籤",poem:["欲攀仙桂蟾宮去","豈慮天門不放開","謀望一般音信好","高人自送嶺頭來"],story:"觀音第23首",classicMeaning:"商賈利益。行戴有危。病安訟遂。盡可施為。",plainMeaning:"此卦手扳仙桂之象。凡事必有貴人也。",categoryReadings:{總論:"商賈利益。行戴有危。病安訟遂。盡可施為。",聖意:"家宅　欠安。自身　作福。求財　遂意。交易　合。婚姻　阻。六甲　作福。行人　有危。田蠶　不利。六畜　不利。尋人　難。公訟　虧。移徙　欠吉。失物　疾病　安。山墳　舊吉。"},actionAdvice:["積極進取，商賈獲利，凡事有貴人相助，但出行須注意安全。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:24,displayNo:"第24籤",level:"上籤",title:"觀音第24籤",poem:["不成鄰里不成家","水泡痴人似落花","若問君恩難得力","到頭畢竟事如蔴"],story:"觀音第24首",classicMeaning:"是非莫說。必須仔細。心正理直。方免災危。",plainMeaning:"此卦痴人道塞之象。凡事守舊待時也。",categoryReadings:{總論:"是非莫說。必須仔細。心正理直。方免災危。",聖意:"家宅　不安。自身　險。求財　阻。交易　難。婚姻　待時。六甲　祈福。行人　阻。田蠶　多災。六畜　多災。尋人　阻。公訟　虧。移徙　吉。失物　難見。疾病　急求神。山墳　不吉。"},actionAdvice:["是非莫說，心正理直方免災危，目前宜守舊待時，凡事謹慎。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:25,displayNo:"第25籤",level:"上籤",title:"觀音第25籤",poem:["過了憂危第幾重","從今再歷永無凶","寬心自有寬心計","得遇高人護聖功"],story:"觀音第25首",classicMeaning:"訟終有理。病得安全。出入求謀。古井逢泉。",plainMeaning:"此卦古井逢泉之象。凡事貴人成就也。",categoryReadings:{總論:"訟終有理。病得安全。出入求謀。古井逢泉。",聖意:"家宅　平平。自身　阻滯。求財　阻滯。交易　阻滯。婚姻　和合。六甲　有險。行人　阻隔。田蠶　不利。六畜　不利。尋人　阻隔。公訟　有理。移徙　不合。失物　難尋。疾病　祈福。山墳　不安。"},actionAdvice:["憂危已過，古井逢泉，凡事有貴人成就，婚姻和合，訟有理。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:26,displayNo:"第26籤",level:"上籤",title:"觀音第26籤",poem:["上下傳來事總虛","天邊接得一封書","書中許我功名事","直待終時亦是無"],story:"觀音第26首",classicMeaning:"上下心煩。求閒不閒。欲望功名。守舊身安。",plainMeaning:"此卦虛名之象。凡事虛多少實宜守舊也。",categoryReadings:{總論:"上下心煩。求閒不閒。欲望功名。守舊身安。",聖意:"家宅　祈福。自身　安。求財　阻。交易　不成。婚姻　不成。六甲　女。行人　有信。田蠶　半熟。六畜　可養。尋人　西方。公訟　虧。移徙　守舊。失物　難。疾病　祈保。山墳　吉。"},actionAdvice:["功名虛而不實，凡事虛多實少，宜守舊身安，莫強求不切實際之事。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:27,displayNo:"第27籤",level:"上籤",title:"觀音第27籤",poem:["一謀一用一番機","慮後疑前不敢為","時至自然逢貴助","銀牆鐵壁好安居"],story:"觀音第27首",classicMeaning:"改舊成新。寒花遇春。從前阻滯。今得稱心。",plainMeaning:"此卦屋好牆壁之象。凡事穩當無險也。",categoryReadings:{總論:"改舊成新。寒花遇春。從前阻滯。今得稱心。",聖意:"家宅　安。自身　吉。求財　有。交易　難。婚姻　阻。六甲　女。行人　遲。田蠶　熟。六畜　利。尋人　遲。公訟　宜和。移徙　吉。失物　無蹤。疾病　延安。山墳　守舊大吉。"},actionAdvice:["改舊成新，從前阻滯已消，凡事穩當無險，時至自然逢貴助。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:28,displayNo:"第28籤",level:"上籤",title:"觀音第28籤",poem:["東方月上正月上正嬋娟","頃刻雲遮月半邊","莫道圓時還又缺","須教缺處復重圓"],story:"觀音第28首",classicMeaning:"浮雲遮月。不須疑惑。等待雲收。便見明白。",plainMeaning:"此卦月被雲遮之象。凡事昏迷未定也。",categoryReadings:{總論:"浮雲遮月。不須疑惑。等待雲收。便見明白。",聖意:"家宅　不安。自身　祈保。求財　阻。交易　吉。婚姻　不合。六甲　有驚。行人　滯。田蠶　不利。六畜　不利。尋人　難。公訟　虧。移徙　守舊。失物　西方。疾病　難痊。山墳　改。"},actionAdvice:["浮雲遮月終會散，不須疑惑，耐心等待雲收，便見明白，守舊為上。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:29,displayNo:"第29籤",level:"上籤",title:"觀音第29籤",poem:["寶劍光芒出匣時","匣中應不被塵欺","貴人親手提攜起","儘可防身更無疑"],story:"觀音第29首",classicMeaning:"寶劍出匣。光輝萬里。貴人指引。無不觀美。",plainMeaning:"此卦寶劍出匣之象。凡事有威有勢也。",categoryReadings:{總論:"寶劍出匣。光輝萬里。貴人指引。無不觀美。",聖意:"家宅　祈福。自身　吉。求財　利。交易　成。婚姻　好。六甲　女。行人　遲。田蠶　宜早。六畜　損。尋人　見。公訟　和。移徙　興。失物　南方。疾病　還舊願。山墳　吉。"},actionAdvice:["寶劍出匣光輝萬里，貴人指引無不觀美，積極行動必有好結果。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:30,displayNo:"第30籤",level:"上籤",title:"觀音第30籤",poem:["勸君切莫向他求","似鶴飛來暗箭投","若去採薪蛇伏草","恐遭毒手也堪憂"],story:"觀音第30首",classicMeaning:"閉口含齒。他事莫理。若有虧心。到頭害己。",plainMeaning:"此卦安份守己之象。凡事小心謹防也。",categoryReadings:{總論:"閉口含齒。他事莫理。若有虧心。到頭害己。",聖意:"家宅　安。自身　平平。求財　待時。交易　滯。婚姻　未許。六甲　虛驚。行人　阻隔。田蠶　不利。六畜　不利。尋人　阻隔。公訟　虧（莫興）。移徙　守舊。失物　不見。疾病　難痊。山墳　大吉。"},actionAdvice:["安份守己，閉口莫理他事，若有虧心到頭害己，凡事小心謹防。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:31,displayNo:"第31籤",level:"上籤",title:"觀音第31籤",poem:["清閑無事靜處坐","飢時吃飯困時臥","放下身心不用忙","必定不遭殃與禍"],story:"觀音第31首",classicMeaning:"守舊安然。叩問神仙。直待時來。事亦偶然。",plainMeaning:"此卦守舊安然之象。凡事時待時則吉也。",categoryReadings:{總論:"守舊安然。叩問神仙。直待時來。事亦偶然。",聖意:"家宅　祈保。自身　安。求財　守待。交易　宜遲。婚姻　合。六甲　女。行人　至。田蠶　秋熟。六畜　穩。尋人　難。公訟　和。移徙　吉。失物　虛。疾病　設送。山墳　吉。"},actionAdvice:["守舊安然，靜心等待時機，飢時吃飯困時臥，放下身心不遭殃禍。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:32,displayNo:"第32籤",level:"上籤",title:"觀音第32籤",poem:["渺渺前途事可疑","石中藏玉有誰知","一朝良臣分明剖","始覺其中碧玉奇"],story:"觀音第32首",classicMeaning:"寶在石中。異人少知。直待分明。盡可施為。",plainMeaning:"此卦剖石見玉之象。凡事著力成功也。",categoryReadings:{總論:"寶在石中。異人少知。直待分明。盡可施為。",聖意:"家宅　平平。自身　安。求財　勞力。交易　阻。婚姻　成。六甲　虛。行人　杳。田蠶　晚成。六畜　旺。尋人　見。公訟　驚。移徙　改。失物　西方。疾病　欠安。山墳　改向吉。"},actionAdvice:["石中藏玉終會分明，凡事著力方能成功，積極努力必有收穫。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:33,displayNo:"第33籤",level:"上籤",title:"觀音第33籤",poem:["石藏美玉在中心","得指何須向外尋","直待高人來剖析","恰如靈雨滌煩襟"],story:"觀音第33首",classicMeaning:"內藏金玉。不識外尋。遇貴指引。不須勞心。",plainMeaning:"此卦藏玉內尋之象。凡事待時可也。",categoryReadings:{總論:"內藏金玉。不識外尋。遇貴指引。不須勞心。",聖意:"家宅　祈保。自身　安。求財　守待。交易　遲。婚姻　就。六甲　男。行人　阻。田蠶　半熟。六畜　旺。尋人　勞。公訟　擱。移徙　吉。失物　北方。疾病　遇良醫。山墳　宜改。"},actionAdvice:["內藏金玉不必外尋，遇貴指引不須勞心，耐心等待時機成熟。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:34,displayNo:"第34籤",level:"上籤",title:"觀音第34籤",poem:["出入行藏禮義恭","言必忠良聽必聰","心下了然俱洞徹","光明如日正當空"],story:"觀音第34首",classicMeaning:"心中無事。秋水澄清。不須疑惑。事自然成。",plainMeaning:"此卦紅日當空正照之象。凡事遂意也。",categoryReadings:{總論:"心中無事。秋水澄清。不須疑惑。事自然成。",聖意:"家宅　清吉。自身　安。求財　虛。交易　難。婚姻　合。六甲　有險。行人　阻。田蠶　不利。六畜　衰。尋人　滯。公訟　虧。移徙　守舊。失物　虛。疾病　設送。山墳　大吉。"},actionAdvice:["心中坦蕩如秋水澄清，行事光明磊落，不須疑惑，事自然成。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:35,displayNo:"第35籤",level:"上籤",title:"觀音第35籤",poem:["衣冠重整就宿風","道是無功卻有功","掃卻當途荊棘碍","三人共議事相同"],story:"觀音第35首",classicMeaning:"不用憂疑。自有佳期。若問前程。前路可宜。",plainMeaning:"此卦衣冠重整之象。凡事先難后易也。",categoryReadings:{總論:"不用憂疑。自有佳期。若問前程。前路可宜。",聖意:"家宅　亂。自身　吉。求財　好。交易　利。婚姻　阻。六甲　驚。行人　至。田蠶　不利。六畜　興。尋人　至。公訟　有理。移徙　安。失物　遲見。疾病　祈福。山墳　宜舊。"},actionAdvice:["不用憂疑，自有佳期，凡事掃除障礙，先難後易，前路可宜。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:36,displayNo:"第36籤",level:"上籤",title:"觀音第36籤",poem:["目前病訟不須憂","實地資財儘可求","恰好繫猿今脫鎖","得歸仙洞去來遊"],story:"觀音第36首",classicMeaning:"脫除了事。且自寬心。待得時來。堪尋正路。",plainMeaning:"此卦猿猴脫鎖之象。凡事先難後易也。",categoryReadings:{總論:"脫除了事。且自寬心。待得時來。堪尋正路。",聖意:"家宅　不安。自身　安。求財　大利。交易　待時。婚姻　未成。六甲　祈保。行人　至。田蠶　十足。六畜　平。尋人　至。公訟　有理。移徙　吉。失物　遠。疾病　欠安。山墳　吉。"},actionAdvice:["脫除束縛且寬心，待得時來堪尋正路，凡事先難後易，求財大利。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:37,displayNo:"第37籤",level:"上籤",title:"觀音第37籤",poem:["欲問身安運泰時","風中燈燭不相宜","爭如收拾深堂坐","庶免光搖近處期"],story:"觀音第37首",classicMeaning:"靜處安身。待命守時。支惹非福。守舊相宜。",plainMeaning:"此卦風搖燈燭之象。凡事守常則吉也。",categoryReadings:{總論:"靜處安身。待命守時。支惹非福。守舊相宜。",聖意:"家宅　守舊。自身　平平。求財　有。交易　難。婚姻　不合。六甲　祈保。行人　有信。田蠶　秋熟。六畜　安。尋人　見。公訟　和。移徙　守舊。失物　疾病　禳星。山墳　勿改。"},actionAdvice:["靜處安身，待命守時，守舊為宜，支惹非福，凡事守常則吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:38,displayNo:"第38籤",level:"上籤",title:"觀音第38籤",poem:["鏡月當空出匣時","剎那雲霧暗迷離","寬心守待浮雲散","更改相宜可望為"],story:"觀音第38首",classicMeaning:"此卦雲霧遮月之象。凡事未遂守舊也。",plainMeaning:"此卦雲霧遮月之象。凡事未遂守舊也。",categoryReadings:{總論:"此卦雲霧遮月之象。凡事未遂守舊也。",聖意:"家宅　不安。自身　祈保。求財　難。交易　待時。婚姻　難合。六甲　虛驚。行人　阻。田蠶　損。六畜　損。尋人　遇。公訟　和。移徙　安。失物　虛。疾病　延安。山墳　宜修。"},actionAdvice:["雲霧遮月終會散去，寬心守待，凡事未遂宜守舊，切勿急躁。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:39,displayNo:"第39籤",level:"上籤",title:"觀音第39籤",poem:["天邊消息應難問","切莫私心強望求","若把石頭磨作鏡","精神枉費一時休"],story:"觀音第39首",classicMeaning:"千般用計。枉費功夫。不如守舊。著甚來由。",plainMeaning:"此卦守常安靜之象。凡事守己則吉也。",categoryReadings:{總論:"千般用計。枉費功夫。不如守舊。著甚來由。",聖意:"家宅　安。自身　提防。求財　平平。交易　阻。婚姻　不合。六甲　女。行人　動。田蠶　利。六畜　損。尋人　難。公訟　虧。移徙　平。失物　空。疾病　設送。安。山墳　大吉。"},actionAdvice:["千般用計枉費功夫，不如守舊安靜，凡事守己則吉，莫強求。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:40,displayNo:"第40籤",level:"上籤",title:"觀音第40籤",poem:["紅輪西墜兔東升","陰長陽消是兩形","若是女人占此卦","增添福祿稱心情"],story:"觀音第40首",classicMeaning:"陰利女人。不宜男子。若是求謀。先凶後吉。",plainMeaning:"此卦陰長陽消之象。凡事先難后易也。",categoryReadings:{總論:"陰利女人。不宜男子。若是求謀。先凶後吉。",聖意:"家宅　不利。自身　祈福。求財　守待。交易　吉。婚姻　不合。六甲　虛（女）。行人　阻。田蠶　旺。六畜　旺。尋人　隔。公訟　虧。移徙　大吉。失物　空。疾病　有驚。山墳　大吉。"},actionAdvice:["陰利女性，男性宜謹慎，凡事先凶後吉，耐心等待轉機出現。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:41,displayNo:"第41籤",level:"上籤",title:"觀音第41籤",poem:["無限好事君須記","恰如認賊作為子","莫貪眼下有些甜","可慮他時還受苦"],story:"觀音第41首",classicMeaning:"只這一著。君子莫錯。牢記在心。不生寂寞。",plainMeaning:"此卦認賊作子之象。凡事認真作假。",categoryReadings:{總論:"只這一著。君子莫錯。牢記在心。不生寂寞。",聖意:"家宅　不安。自身　平常。求財　守待。交易　難。婚姻　未合。六甲　男。驚。行人　至。田蠶　半熟。六畜　安。尋人　至。公訟　宜和。移徙　祈保。失物　難尋。疾病　禳星。山墳　中平。"},actionAdvice:["莫貪眼下甜頭，認賊作子必有後患，牢記在心，凡事認真辨別。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:42,displayNo:"第42籤",level:"上籤",title:"觀音第42籤",poem:["君垂恩澤潤無邊","覆禱祈禳沒黨偏","一切有情皆受用","均沾樂利得週全"],story:"觀音第42首",classicMeaning:"天皇降恩。始終莫忘。晨昏禮念。可宜燒香。",plainMeaning:"此卦天垂恩澤之象。凡事成就大吉也。",categoryReadings:{總論:"天皇降恩。始終莫忘。晨昏禮念。可宜燒香。",聖意:"家宅　祈福。自身　冬吉。求財　未有。交易　成。婚姻　中吉。六甲　平安。行人　動。田蠶　中平。六畜　中平。尋人　見。公訟　勝。移徙　守舊。失物　空。疾病　解。山墳　安。"},actionAdvice:["天降恩澤，始終莫忘感恩，晨昏禮念，凡事成就大吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:43,displayNo:"第43籤",level:"上籤",title:"觀音第43籤",poem:["天地交泰萬物新","自形自色自怡神","森羅萬象皆精彩","事事和諧得稱人"],story:"觀音第43首",classicMeaning:"天生萬物。謀望皆通。福德相助。瑞氣匆匆。",plainMeaning:"此卦大地交泰之象。凡事大吉無危也。",categoryReadings:{總論:"天生萬物。謀望皆通。福德相助。瑞氣匆匆。",聖意:"家宅　吉。自身　安。求財　有。交易　利。婚姻　合。六甲　男。行人　有阻。田蠶　中平。六畜　中平。尋人　見。公訟　勝。移徙　利。失物　東西。疾病　禳星。山墳　東西吉。"},actionAdvice:["天地交泰萬物更新，謀望皆通，福德相助，凡事大吉無危。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:44,displayNo:"第44籤",level:"上籤",title:"觀音第44籤",poem:["棋逢對手要藏機","黑白盤中未決時","到底欲知誰勝負","須教先著相機宜"],story:"觀音第44首",classicMeaning:"欲求心事。恰如圍棋。到底勝利。宜用心機。",plainMeaning:"此卦棋逢敵手之象。凡事用機關則吉也。",categoryReadings:{總論:"欲求心事。恰如圍棋。到底勝利。宜用心機。",聖意:"家宅　大利。自身　平穩。求財　遂。交易　利。婚姻　未合。六甲　女。行人　阻。田蠶　平。六畜　損。尋人　阻。公訟　宜和。移徙　守舊。失物　空。疾病　祈保。山墳　守舊。"},actionAdvice:["棋逢對手需用智慧，凡事宜用心機方能獲勝，婚姻之事暫緩為宜。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:45,displayNo:"第45籤",level:"上籤",title:"觀音第45籤",poem:["溫柔自是勝強剛","積善于門太吉昌","若是有人占此卦","宛如止渴遇瓊漿"],story:"觀音第45首",classicMeaning:"天地有感。應驗非常。佛神護佑。得之莫忘。",plainMeaning:"此卦積善溫柔之象。凡事貴人和合也。",categoryReadings:{總論:"天地有感。應驗非常。佛神護佑。得之莫忘。",聖意:"家宅　吉。自身　安。求財　遂。交易　利。婚姻　合。六甲　男。行人　阻。田蠶　秋利。六畜　中平。尋人　見。公訟　勝。移徙　利。失物　東方。疾病　祈福。山墳　東西向吉。"},actionAdvice:["積善之家必有餘慶，溫柔勝強剛，天地有感，佛神護佑，凡事和合。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:46,displayNo:"第46籤",level:"上籤",title:"觀音第46籤",poem:["勸君耐守舊生涯","把定身心莫聽邪","直待有人輕著力","滿園枯木再開花"],story:"觀音第46首",classicMeaning:"守舊守靜。事自成就。動則多殃。靜則無咎。",plainMeaning:"此卦枯木生花之象。凡事自有成就也。",categoryReadings:{總論:"守舊守靜。事自成就。動則多殃。靜則無咎。",聖意:"家宅　安。自身　吉。求財　待時。交易　成。婚姻　就。六甲　生女。行人　阻。田蠶　五分。六畜　難。尋人　杳。公訟　吉。移徙　守舊。失物　空。疾病　求福。山墳　吉。"},actionAdvice:["守舊守靜事自成就，動則多殃靜則無咎，耐心等待枯木再開花。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:47,displayNo:"第47籤",level:"上籤",title:"觀音第47籤",poem:["錦上添花色更鮮","運來祿馬喜雙全","時人莫訝功名晚","一舉登科四海傳"],story:"觀音第47首",classicMeaning:"守舊變新。運至材成。遂平生志。盡皆是命。",plainMeaning:"此卦錦上添花之象。凡事大吉大利也。",categoryReadings:{總論:"守舊變新。運至材成。遂平生志。盡皆是命。",聖意:"家宅　祈保（吉）。自身　安。求財　利。交易　阻。婚姻　合。六甲　生男。行人　遲。田蠶　八分。六畜　平。尋人　至。公訟　宜和。移徙　吉。失物　西北。疾病　作福。山墳　利。"},actionAdvice:["運至時來，錦上添花，功名晚成終可期，一舉登科四海傳名。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:48,displayNo:"第48籤",level:"上籤",title:"觀音第48籤",poem:["鵾鳥秋光化作鵬","遨翔得意盡飛騰","直沖萬里雲霄外","任是諸禽總不能"],story:"觀音第48首",classicMeaning:"昆化為鵬。萬禽不能。桂香一折。福祿自增。",plainMeaning:"此卦昆鵬興變之象。凡事有變動事。",categoryReadings:{總論:"昆化為鵬。萬禽不能。桂香一折。福祿自增。",聖意:"家宅　利。自身　吉。求財　秋旺。交易　遲。婚姻　不合。六甲　安。行人　阻滯。田蠶　中平。六畜　春利。尋人　見。公訟　勝。移徙　守舊。失物　西。疾病　祈保。山墳　安。"},actionAdvice:["鵾鳥化鵬翱翔萬里，福祿自增，凡事有變動之象，積極把握時機。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:49,displayNo:"第49籤",level:"上籤",title:"觀音第49籤",poem:["營圖萬事若冰澌","何必慳貪苦所為","只好靜心閑處坐","待他興變復奚疑"],story:"觀音第49首",classicMeaning:"水結成冰。冰消成水。若是營謀。到底如是。",plainMeaning:"此卦水結成冰之象。凡事不用枉求也。",categoryReadings:{總論:"水結成冰。冰消成水。若是營謀。到底如是。",聖意:"家宅　不安。自身　祈保。求財　難。交易　阻。婚姻　不合。六甲　險。行人　遲。田蠶　虧。六畜　損。尋人　見。公訟　和。移徙　守舊。失物　空。疾病　難痊。山墳　大吉。"},actionAdvice:["水結成冰冰消成水，凡事不用枉求，靜心等待興變之時再行動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:50,displayNo:"第50籤",level:"上籤",title:"觀音第50籤",poem:["五湖四海盡行船","高掛風帆把舵堅","幸得順風隨所至","滿船寶貝稱心田"],story:"觀音第50首",classicMeaning:"自在休悠。不須著力。財祿重重。無不欣美。",plainMeaning:"此卦順風撐船之象。凡事皆順大吉也。",categoryReadings:{總論:"自在休悠。不須著力。財祿重重。無不欣美。",聖意:"家宅　利。自身　吉（待運至）。求財　利西。交易　宜遲。婚姻　不合。六甲　安。行人　阻。田蠶　秋利。六畜　春旺。尋人　至。公訟　虧。移徙　守舊。失物　西方。疾病　解。山墳　南利。"},actionAdvice:["順風撐船自在悠閒，財祿重重，凡事皆順大吉，不須著力強求。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:51,displayNo:"第51籤",level:"上籤",title:"觀音第51籤",poem:["夏日初臨日正長","人皆愁惱熱非常","天公也解諸人意","故遣薰風特送涼"],story:"觀音第51首",classicMeaning:"進退莫疑。自有佳期。營謀用麼。不須妄為。",plainMeaning:"此卦人人愁熱之象。凡事隨心從意也。",categoryReadings:{總論:"進退莫疑。自有佳期。營謀用麼。不須妄為。",聖意:"家宅　祈福。自身　謹防（凶中有吉）。求財　秋吉。交易　平常。婚姻　合。六甲　生男。行人　動。田蠶　損。六畜　平。尋人　見。公訟　吉。移徙　舊。失物　北方。疾病　還願。山墳　吉。"},actionAdvice:["進退莫疑，自有佳期，凡事隨心從意，切勿妄為錯失良機。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:52,displayNo:"第52籤",level:"上籤",title:"觀音第52籤",poem:["水中捉月費工夫","費盡功夫卻又無","莫信閑言併浪論","枉拋心力也難圖"],story:"觀音第52首",classicMeaning:"言諾難思。費力勞心。宅中憂慮。等遇貴人。",plainMeaning:"此卦貪求費力之象。凡事勞心費力也。",categoryReadings:{總論:"言諾難思。費力勞心。宅中憂慮。等遇貴人。",聖意:"家宅　不安。自身　欠吉（凶。注意健康）。求財　中平（休想）。交易　難。婚姻　未就。六甲　祈保（空寶。防小產）。行人　有災。田蠶　五分。六畜　衰。尋人　至（凶）。公訟　和（即止訟）。移徙　平常（甭提）。失物　難（空）。疾病　祈保（凶）。山墳　吉。"},actionAdvice:["水中撈月終是空，莫信閒言枉費心力，凡事守舊等待貴人相助。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:53,displayNo:"第53籤",level:"上籤",title:"觀音第53籤",poem:["失意翻成得意時","龍吟虎嘯兩相宜","青雲有路終須到","許我功名必可期"],story:"觀音第53首",classicMeaning:"教去即去。自有亨通。到頭必制。立地可謀。",plainMeaning:"此卦龍吟虎嘯之象。凡事順意有望也。",categoryReadings:{總論:"教去即去。自有亨通。到頭必制。立地可謀。",聖意:"家宅　不安。自身　欠吉（先凶后吉）。求財　中平。交易　難。婚姻　成就。六甲　祈保。行人　至。田蠶　五分。六畜　損。尋人　至。公訟　和。移徙　吉。失物　見。疾病　安。山墳　吉。"},actionAdvice:["失意翻成得意時，龍吟虎嘯兩相宜，凡事先凶後吉，婚姻可成。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:54,displayNo:"第54籤",level:"上籤",title:"觀音第54籤",poem:["夢中得寶醒來無","應說巫山只是虛","若問婚姻幷病訟","別尋生路相得宜"],story:"觀音第54首",classicMeaning:"物在水中。形影長短。皆有分定。不用商量。",plainMeaning:"此卦夢中得寶之象。凡事枉費心力也。",categoryReadings:{總論:"物在水中。形影長短。皆有分定。不用商量。",聖意:"家宅　欠安。自身　謹防。求財　阻。交易　難。婚姻　待時。六甲　祈保。行人　遲。田蠶　滯。六畜　滯。尋人　見。公訟　虧。移徙　吉。失物　空。疾病　求神保佑。山墳　不安。"},actionAdvice:["夢中得寶醒來皆空，凡事枉費心力，別尋生路方為上策。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:55,displayNo:"第55籤",level:"上籤",title:"觀音第55籤",poem:["相傳罔替子孫贊","衣祿豐盈富在天","金馬玉堂人快樂","飢時吃飯困時眠"],story:"觀音第55首",classicMeaning:"接竹引泉。流傳不絕。君子謀望。無不欣悅。",plainMeaning:"此卦接竹引泉之象。凡事謀望大吉也。",categoryReadings:{總論:"接竹引泉。流傳不絕。君子謀望。無不欣悅。",聖意:"家宅　欠安（大吉）。自身　還願（大吉）。求財　利。交易　成。婚姻　合（遇佳婿）。六甲　平安（生肖子）。行人　動。田蠶　吉。六畜　損。尋人　難（見）。公訟　有貴人。移徙　吉。失物　見。疾病　禳星（得祖蔭）。山墳　安。"},actionAdvice:["接竹引泉流傳不絕，凡事謀望大吉，求財有利，婚姻和合。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:56,displayNo:"第56籤",level:"上籤",title:"觀音第56籤",poem:["澗小石粗流水響","力勞撐駕恐損傷","路須指出前江去","風靜潮平儘不妨"],story:"觀音第56首",classicMeaning:"營謀用事。勞心費力。守舊待時。凡事大吉。",plainMeaning:"此卦船行小灘之象。凡事有貴人助也。",categoryReadings:{總論:"營謀用事。勞心費力。守舊待時。凡事大吉。",聖意:"家宅　安。自身　吉。求財　中平。交易　利。婚姻　遂（慎）。六甲　男。行人　至。田蠶　秋利。六畜　損。尋人　至。公訟　有理。移徙　吉。失物　帶。疾病　即安。山墳　宜修。"},actionAdvice:["營謀用事雖勞心費力，但守舊待時凡事大吉，有貴人相助。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:57,displayNo:"第57籤",level:"上籤",title:"觀音第57籤",poem:["聞是聞非風過耳","好衣好祿日當空","君須記取他年事","汝意還同我意同"],story:"觀音第57首",classicMeaning:"所用謀望。皆大歡喜。從公用力。如子逢娘。",plainMeaning:"此卦孩兒見母之象。諸事貴人大吉也。",categoryReadings:{總論:"所用謀望。皆大歡喜。從公用力。如子逢娘。",聖意:"家宅　不安。自身　平平。求財　順。交易　成。婚姻　合。六甲　女。行人　阻。田蠶　就。六畜　損。尋人　難。公訟　宜和。移徙　守舊。失物　空。疾病　祈福。山墳　吉。"},actionAdvice:["所用謀望皆大歡喜，凡事有貴人相助，如子逢娘般順遂。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:58,displayNo:"第58籤",level:"上籤",title:"觀音第58籤",poem:["忠言善語君須記","莫向他方求別藝","勸君安守舊生涯","除卻有餘都不是"],story:"觀音第58首",classicMeaning:"得住且住。可取且踞。莫宜別事。只宜守舊。",plainMeaning:"此卦守舊守時之象。凡事守舊則吉也。",categoryReadings:{總論:"得住且住。可取且踞。莫宜別事。只宜守舊。",聖意:"家宅　平常。自身　不利。求財　吉。交易　成。婚姻　阻。六甲　驚。行人　遲。田蠶　五分。六畜　損。尋人　見。公訟　虧。移徙　守舊。失物　凶。疾病　欠安。山墳　宜改。"},actionAdvice:["得住且住，只宜守舊，莫宜別事，安守舊生涯方為上策。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:59,displayNo:"第59籤",level:"上籤",title:"觀音第59籤",poem:["直上高樓去避身","四邊繞處是荊榛","誰知造物安排定","得意番成失意人"],story:"觀音第59首",classicMeaning:"如醉飲酒。只宜守舊。直待時來。無災無咎。",plainMeaning:"此卦守舊隨時之象。凡事待時則吉。",categoryReadings:{總論:"如醉飲酒。只宜守舊。直待時來。無災無咎。",聖意:"家宅　祈福。自身　安（運滯。唯仁可解）。求財　平常（切忌）。交易　成（且慢）。婚姻　不合。六甲　作福。行人　至。田蠶　半吉。六畜　大利（失利）。尋人　阻。公訟　虧。移徙　吉（不吉）。失物　凶。疾病　祈福。山墳　吉。"},actionAdvice:["如醉飲酒只宜守舊，直待時來無災無咎，凡事耐心等待為上。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:60,displayNo:"第60籤",level:"上籤",title:"觀音第60籤",poem:["抱薪救火火增烟","燒卻三千及大千","若問營謀併出入","不如收拾莫憂燃"],story:"觀音第60首",classicMeaning:"有千般計。一旦相惹。不如莫動。恐惹禍身。",plainMeaning:"此卦抱薪救火之象。凡事亦自謹防也。",categoryReadings:{總論:"有千般計。一旦相惹。不如莫動。恐惹禍身。",聖意:"家宅　凶。自身　祈保。求財　微微。交易　不合。婚姻　不合。六甲　險。行人　滯。田蠶　不利。六畜　損。尋人　杳。公訟　虧。移徙　吉。失物　西方。疾病　有驚。山墳　平平。"},actionAdvice:["有千般計不如莫動，恐惹禍身，凡事亦宜謹防，守舊為上策。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:61,displayNo:"第61籤",level:"上籤",title:"觀音第61籤",poem:["日上吟詩月下歌","逢場作戲笑呵呵","相逢會處難藏隱","喝啋齊聲嗹哩囉"],story:"觀音第61首",classicMeaning:"佳人在屋。吟唱詩曲。一片歡心。命中禍福。",plainMeaning:"此卦守舊隨時之象。凡事時吉利也。",categoryReadings:{總論:"佳人在屋。吟唱詩曲。一片歡心。命中禍福。",聖意:"家宅　安。自身　吉。求財　順。交易　利。婚姻　成。六甲　女。行人　至。田蠶　熟。六畜　旺。尋人　至。公訟　有理。移徙　吉。失物　凶。疾病　即痊愈。山墳　大吉。"},actionAdvice:["逢場作戲一片歡心，凡事時吉利也，家宅安寧，婚姻可成。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:62,displayNo:"第62籤",level:"上籤",title:"觀音第62籤",poem:["晨昏全賴佛扶持","雖是逢危不見危","若得貴人來接引","此時福祿自相隨"],story:"觀音第62首",classicMeaning:"守舊平安之象。凡事遇貴則吉。",plainMeaning:"此卦神佛暗佑之象。凡事忍耐大吉也。",categoryReadings:{總論:"守舊平安之象。凡事遇貴則吉。",聖意:"家宅　安。自身　吉。求財　西方。交易　遂。婚姻　成。六甲　祈福。行人　阻。田蠶　七分。六畜　利。尋人　西方。公訟　虧。移徙　守舊。失物　見。疾病　祈福。山墳　吉。"},actionAdvice:["守舊平安，凡事忍耐大吉，雖逢危不見危，有貴人暗中相助。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:63,displayNo:"第63籤",level:"上籤",title:"觀音第63籤",poem:["昔日行船失了針","今朝依舊海中尋","若還尋得原針在","也費工夫也費心"],story:"觀音第63首",classicMeaning:"福是祿基。祿是福種。說得分明。切宜守謹。",plainMeaning:"此卦海中尋針之象。凡事費心勞力也。",categoryReadings:{總論:"福是祿基。祿是福種。說得分明。切宜守謹。",聖意:"家宅　欠利。自身　謹防。求財　有。交易　成。婚姻　不合。六甲　阻。行人　滯。田蠶　吉。六畜　莫養。尋人　難。公訟　宜和。移徙　宜遷。失物　凶。疾病　難痊。山墳　暫安。"},actionAdvice:["福是祿基祿是福種，切宜守謹，凡事費心勞力但終有收穫。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:64,displayNo:"第64籤",level:"上籤",title:"觀音第64籤",poem:["譬若金鱗放碧漪","暗遭羅網四邊圍","思量無計翻身出","命到泉關苦獨悲"],story:"觀音第64首",classicMeaning:"屋下安身。禍從天降。早覺先防。免遭災殃。",plainMeaning:"此卦魚遭羅網之象。凡事亦宜提防也。",categoryReadings:{總論:"屋下安身。禍從天降。早覺先防。免遭災殃。",聖意:"家宅　凶。自身　險。求財　虛。交易　中平。婚姻　不合。六甲　驚。行人　有阻。田蠶　損。六畜　衰。尋人　杳。公訟　虧。移徙　吉。失物　凶。疾病　有災險。山墳　宜改。"},actionAdvice:["禍從天降須早覺先防，凡事宜提防小人，謹慎行事免遭災殃。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:65,displayNo:"第65籤",level:"上籤",title:"觀音第65籤",poem:["眼前歡喜未為歡","危不危兮安不安","割肉成瘡因甚事","不如守舊得安全"],story:"觀音第65首",classicMeaning:"知止則止。知寬自寬。割自身肉。疾痛一般。",plainMeaning:"此卦割肉成瘡之象。凡事只宜守舊待時。",categoryReadings:{總論:"知止則止。知寬自寬。割自身肉。疾痛一般。",聖意:"家宅　不安。自身　口舌。求財　不利。交易　小人。婚姻　不長。六甲　有驚。行人　阻。田蠶　損。六畜　損。尋人　招非。公訟　虧。移徙　守舊。失物　難尋。疾病　反覆。山墳　不利。"},actionAdvice:["知止則止，割肉成瘡不如守舊，凡事只宜守舊待時，切勿妄動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:66,displayNo:"第66籤",level:"上籤",title:"觀音第66籤",poem:["路險馬行人去遠","失群羊困虎相當","危灘船過風翻浪","春暮花殘天降霜"],story:"觀音第66首",classicMeaning:"守舊守舊。安靜無咎。不用求謀。自在優游。",plainMeaning:"此卦船破下灘之象。凡事險阻提防也。",categoryReadings:{總論:"守舊守舊。安靜無咎。不用求謀。自在優游。",聖意:"家宅　憂疑。自身　災耗。求財　破失。交易　敗。婚姻　不長。六甲　危險。行人　阻。田蠶　損。六畜　損。尋人　杳。公訟　虧。移徙　莫動。失物　疾病　即設送。山墳　不利。"},actionAdvice:["守舊守舊安靜無咎，目前險阻重重，凡事提防，莫要輕舉妄動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:67,displayNo:"第67籤",level:"上籤",title:"觀音第67籤",poem:["一條金秤等君情","無增無減無重輕","為是平生心正直","文章不識義皆明"],story:"觀音第67首",classicMeaning:"心平正直。到底清平。只依本份。天下太平。",plainMeaning:"此卦心平正直之象。凡事平穩無凶也。",categoryReadings:{總論:"心平正直。到底清平。只依本份。天下太平。",聖意:"家宅　安。自身　平。求財　守慎。交易　穩。婚姻　合。六甲　男。行人　有信。田蠶　穩。六畜　安。尋人　遲。公訟　和。移徙　守舊。失物　見。疾病　禳星。山墳　平。"},actionAdvice:["心平正直到底清平，只依本份天下太平，凡事平穩無凶。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:68,displayNo:"第68籤",level:"上籤",title:"觀音第68籤",poem:["門庭清吉夢禎祥","積善于門大吉昌","訟理婚成蠶又熟","病逢良藥得安康"],story:"觀音第68首",classicMeaning:"春深日暖。百花自開。事莫遲疑。從人顯達。",plainMeaning:"此卦春夢百花之象。凡事遇貴人大吉也。",categoryReadings:{總論:"春深日暖。百花自開。事莫遲疑。從人顯達。",聖意:"家宅　旺。自身　安。求財　春旺。交易　遂。婚姻　成。六甲　防驚。行人　到。田蠶　利。六畜　旺。尋人　至。公訟　勝。移徙　如意。失物　急尋。疾病　安。山墳　大吉。"},actionAdvice:["春深日暖百花自開，事莫遲疑，凡事遇貴人大吉，積極行動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:69,displayNo:"第69籤",level:"上籤",title:"觀音第69籤",poem:["冬來嶺上一枝梅","葉落枯枝總不摧","探得陽春消息近","依然還我做花魁"],story:"觀音第69首",classicMeaning:"一箭射空。當空不空。待等春來。彩在其中。",plainMeaning:"此卦梅花占魁之象。凡事宜遲則吉也。",categoryReadings:{總論:"一箭射空。當空不空。待等春來。彩在其中。",聖意:"家宅　欠利。自身　作福。求財　謹慎。交易　待時。婚姻　遲成。六甲　春實秋虛。行人　遲至。田蠶　旺。六畜　旺。尋人　見。公訟　虧。移徙　失物　東方。疾病　虛驚。山墳　宜改。"},actionAdvice:["冬梅終會迎春綻放，凡事宜遲則吉，耐心等待時機必有收穫。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:70,displayNo:"第70籤",level:"上籤",title:"觀音第70籤",poem:["朝朝役役恰如蜂","飛來飛去西復東","春暮花殘無覔處","此身不戀舊叢中"],story:"觀音第70首",classicMeaning:"無覓春色。久雨不晴。求謀動用。不如安靜。",plainMeaning:"此卦蜜蜂采花之象。凡事勞心費力也。",categoryReadings:{總論:"無覓春色。久雨不晴。求謀動用。不如安靜。",聖意:"家宅　口舌。自身　小人。求財　破耗。交易　反覆。婚姻　不長。六甲　虛花。行人　杳。田蠶　損。六畜　損。尋人　無蹤。公訟　虧。移徙　守舊。失物　空。疾病　有阻。山墳　改。"},actionAdvice:["蜜蜂採花勞心費力終無覓處，不如安靜守舊，凡事不宜妄動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:71,displayNo:"第71籤",level:"上籤",title:"觀音第71籤",poem:["誰知愛寵遇強徒","女子當年嫁二夫","自是一弓施兩箭","騎龍跨馬上安居"],story:"觀音第71首",classicMeaning:"不出重重。事由天命。振六中開。切宜謹守。",plainMeaning:"此卦一弓架兩箭之象。凡事再合則吉也。",categoryReadings:{總論:"不出重重。事由天命。振六中開。切宜謹守。",聖意:"家宅　損失。自身　是非。求財　勞力。交易　謹防。婚姻　再合。六甲　先虛后實。行人　阻。田蠶　晚收。六畜　損。尋人　見。公訟　虧。移徙　改。失物　疾病　禳星。山墳　改。"},actionAdvice:["事由天命，切宜謹守，凡事再合則吉，婚姻可望重新結合。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:72,displayNo:"第72籤",level:"上籤",title:"觀音第72籤",poem:["弄蜂須要求他蜜","只怕遭他尾上針","雖是眼前有異路","暗裏深藏荊棘林"],story:"觀音第72首",classicMeaning:"事須仔細。不用強求。結蜂采蜜。有甚來由。",plainMeaning:"此卦結蜂采蜜之象。凡事勞心費力也。",categoryReadings:{總論:"事須仔細。不用強求。結蜂采蜜。有甚來由。",聖意:"家宅　欠利。自身　防。求財　阻。交易　遲。婚姻　阻隔。六甲　虛驚。行人　遲。田蠶　少收。六畜　少收。尋人　難。公訟　虧。移徙　莫動。失物　凶。疾病　設送。山墳　敗。"},actionAdvice:["事須仔細不用強求，弄蜂求蜜恐遭尾針，凡事勞心費力需謹慎。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:73,displayNo:"第73籤",level:"上籤",title:"觀音第73籤",poem:["春雷震起蟄中蟲","脫卻塵凡出舊墉","忽遇風雲交際處","自然變化得成龍"],story:"觀音第73首",classicMeaning:"雷發時轉。出入兩存。一朝變化。直到天門。",plainMeaning:"此卦雷發百蟲之象。凡事遇貴人吉兆也。",categoryReadings:{總論:"雷發時轉。出入兩存。一朝變化。直到天門。",聖意:"家宅　祈福。自身　平常。求財　春利。交易　貴人。婚姻　成合。六甲　男。行人　到。田蠶　早生。六畜　春利。尋人　見。公訟　勝。移徙　吉。失物　疾病　險阻。山墳　吉。"},actionAdvice:["春雷震起萬物復甦，一朝變化直到天門，凡事遇貴人吉兆。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:74,displayNo:"第74籤",level:"上籤",title:"觀音第74籤",poem:["慵飛野鶴自投籠","欲舉鵬霄落陷中","南北東西混障碍","此身憔悴恨無窮"],story:"觀音第74首",classicMeaning:"進身可得。退步為能。低頭直去。悉在其中。",plainMeaning:"此卦似鵠投水(籠)之象。凡事多虛少實也。",categoryReadings:{總論:"進身可得。退步為能。低頭直去。悉在其中。",聖意:"家宅　不安。自身　困滯。求財　小人。交易　破耗。婚姻　刑傷。六甲　刑劫。行人　阻。田蠶　缺。六畜　瘟。尋人　杳。公訟　禍。移徙　不利。失物　凶。疾病　延。山墳　絕。"},actionAdvice:["野鶴投籠處處受限，凡事多虛少實，宜低頭守拙，莫強求。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:75,displayNo:"第75籤",level:"上籤",title:"觀音第75籤",poem:["宛如抱虎過山前","戰戰兢兢膽碎寒","幸得山前逢妙手","方能保得一身安"],story:"觀音第75首",classicMeaning:"危危險險。前程有阻。若問求謀。到底辛苦。",plainMeaning:"此卦抱(拖)虎過山之象。凡事險凶驚恐也。",categoryReadings:{總論:"危危險險。前程有阻。若問求謀。到底辛苦。",聖意:"家宅　祈保。自身　提防。求財　謹慎。交易　滯。婚姻　難順。六甲　有驚。行人　阻。田蠶　五分。六畜　損。尋人　杳。公訟　虧。移徙　守。失物　難。疾病　祭虎。山墳　凶。"},actionAdvice:["抱虎過山險象環生，凡事謹慎提防，前程有阻，宜守不宜進。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:76,displayNo:"第76籤",level:"上籤",title:"觀音第76籤",poem:["魚龍混雜意和同","耐守寒潭未濟中","不覺一朝頭角聳","禹門一跳到天宮"],story:"觀音第76首",classicMeaning:"雖是滋基。也要待時。營謀自本。切莫妄為。",plainMeaning:"此卦魚龍未變之逸象。凡事待時至可也。",categoryReadings:{總論:"雖是滋基。也要待時。營謀自本。切莫妄為。",聖意:"家宅　平安。自身　康泰。求財　有。交易　待時。婚姻　遲合。六甲　生男。行人　遲。田蠶　晚豐。六畜　尾利。尋人　未遇。公訟　延。移徙　守舊。失物　疾病　阻。山墳　發。"},actionAdvice:["魚龍混雜待時變化，凡事待時至可也，切莫妄為，耐心等待。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:77,displayNo:"第77籤",level:"上籤",title:"觀音第77籤",poem:["夢中說夢獲多財","身外浮名總莫猜","永遠山遙難信定","貴人一指笑顏開"],story:"觀音第77首",classicMeaning:"如夢說夢。聲名莫望。只待好時。貴人指示。",plainMeaning:"此卦夢中得寶之象。凡事虛多少實也。",categoryReadings:{總論:"如夢說夢。聲名莫望。只待好時。貴人指示。",聖意:"家宅　祈福。自身　阻。求財　虛。交易　難成。婚姻　不合。六甲　虛。行人　遲。田蠶　不收。六畜　損。尋人　杳。公訟　和。移徙　待時。失物　遠。疾病　設送。山墳　改。"},actionAdvice:["夢中得寶皆虛幻，聲名莫望，只待好時貴人指示，凡事守舊。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:78,displayNo:"第78籤",level:"上籤",title:"觀音第78籤",poem:["冷水來澆白雪洋","不寒不熱自溫涼","要行天下無他事","惟有中藏一藝強"],story:"觀音第78首",classicMeaning:"囚人逢赦。病遇良醫。求財謀望。貴人指示。",plainMeaning:"此卦平善用事之象。凡事平穩大吉也。",categoryReadings:{總論:"囚人逢赦。病遇良醫。求財謀望。貴人指示。",聖意:"家宅　安。自身　吉。求財　遂。交易　成。婚姻　合。六甲　男。行人　至。田蠶　熟。六畜　旺。尋人　至。公訟　散。移徙　大吉。失物　即見。疾病　安然。山墳　大吉利。"},actionAdvice:["囚人逢赦病遇良醫，凡事平穩大吉，貴人指引，積極行動必有收穫。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:79,displayNo:"第79籤",level:"上籤",title:"觀音第79籤",poem:["虛空結愿結人緣","保得人安愿未還","得兔忘蹄真絕跡","敢將初誓謾輕瞞"],story:"觀音第79首",classicMeaning:"人有我見。心不用忙。觀音指示。切莫輕慢。",plainMeaning:"此卦信實莫信虛之。凡事守舊之兆也。",categoryReadings:{總論:"人有我見。心不用忙。觀音指示。切莫輕慢。",聖意:"家宅　還願。自身　許經。求財　守份。交易　謹慎。婚姻　虛。六甲　生女。行人　滯。田蠶　七分。六畜　損。尋人　杳。公訟　和。移徙　守。失物　西方。疾病　解。山墳　西向。"},actionAdvice:["虛空結愿須記得還愿，凡事守舊之兆，切莫輕慢神明指示。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:80,displayNo:"第80籤",level:"上籤",title:"觀音第80籤",poem:["直上高山去學仙","豈知一旦帝王宣","青天白日常明照","志在聲名四海傳"],story:"觀音第80首",classicMeaning:"有始有終。莫向西東。心中用事。貴人重重。",plainMeaning:"此卦貴人接引之象。凡事和合大吉也。",categoryReadings:{總論:"有始有終。莫向西東。心中用事。貴人重重。",聖意:"家宅　平安。自身　吉利。求財　有利。交易　遂意。婚姻　雙配。六甲　男。行人　回。田蠶　半收。六畜　勝。尋人　遇。公訟　勝。移徙　吉。失物　南。疾病　安。山墳　吉。"},actionAdvice:["有始有終，心中用事貴人重重，凡事和合大吉，積極進取。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:81,displayNo:"第81籤",level:"上籤",title:"觀音第81籤",poem:["庭前葉落暮秋時","行客奔程勢若飛","謝得天公輕着力","順風相送寶船歸"],story:"觀音第81首",classicMeaning:"心中取事。天心從之。營謀用事。盡可施為。",plainMeaning:"此卦梧桐葉落之象。凡事先凶後吉也。",categoryReadings:{總論:"心中取事。天心從之。營謀用事。盡可施為。",聖意:"家宅　祈保。自身　許經。求財　遂意。交易　成。婚姻　和合。六甲　虛驚。行人　動。田蠶　晚勝。六畜　穩。尋人　至。公訟　勝。移徙　隨意。失物　疾病　喜。山墳　擇地。"},actionAdvice:["心中取事天心從之，營謀用事盡可施為，凡事先凶後吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:82,displayNo:"第82籤",level:"上籤",title:"觀音第82籤",poem:["炎炎烈火焰燒天","焰裡還生一朵蓮","到底永成根不壞","依然枝葉色新鮮"],story:"觀音第82首",classicMeaning:"雖然逢險。不損其身。營謀用事。皆遇貴人。",plainMeaning:"此卦火裏生蓮之象。凡事似險非險也。",categoryReadings:{總論:"雖然逢險。不損其身。營謀用事。皆遇貴人。",聖意:"家宅　欠安。自身　謹防。求財　勞力。交易　小人。婚姻　阻。六甲　虛驚。行人　阻。田蠶　缺。六畜　損。尋人　西。公訟　虧。移徙　守舊。失物　南。疾病　設送。山墳　改。"},actionAdvice:["火中生蓮雖險不損，凡事似險非險，有貴人相助，謹防小人。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:83,displayNo:"第83籤",level:"上籤",title:"觀音第83籤",poem:["譬若初三四五蟾","半無半有未完全","須教十五良宵夜","到處清光到處圓"],story:"觀音第83首",classicMeaning:"守舊待時。如月初出。待等圓時。無有不吉。",plainMeaning:"此卦月缺未圓之象。凡事守候忍耐也。",categoryReadings:{總論:"守舊待時。如月初出。待等圓時。無有不吉。",聖意:"家宅　許願。自身　夏秋吉。求財　謹守。交易　待時。婚姻　遲。六甲　生女。行人　阻。田蠶　平穩。六畜　平穩。尋人　難。公訟　和。移徙　守舊。失物　難。疾病　設送。山墳　改。"},actionAdvice:["月缺終會圓，守舊待時如月初出，凡事守候忍耐，終有圓滿之時。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:84,displayNo:"第84籤",level:"上籤",title:"觀音第84籤",poem:["因名喪德不和同","切忌忙中變作凶","醉後不知何處去","青松影裡睡矇矓"],story:"觀音第84首",classicMeaning:"寒魚離水。美中不足。若問營謀。不如莫起。",plainMeaning:"此卦寒魚離水之象。凡事不可移動也。",categoryReadings:{總論:"寒魚離水。美中不足。若問營謀。不如莫起。",聖意:"家宅　平吉。自身　利安。求財　不平。交易　諸祭。婚姻　事解。六甲　煞旺。行人　未至。田蠶　平。六畜　平。尋人　公訟　變。移徒　守舊。失物　無。疾病　反覆。山墳　凶。"},actionAdvice:["寒魚離水美中不足，凡事不可移動，守舊為宜，切勿妄動。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:85,displayNo:"第85籤",level:"上籤",title:"觀音第85籤",poem:["重開山後藏前事","萬寶園中可再團","醉詠新詩添逸興","貴人引接上雲衢"],story:"觀音第85首",classicMeaning:"老者用求。春殘再開。欲求名利。晚遇橫財。",plainMeaning:"此卦春盡花開之象。凡事主後改變也。",categoryReadings:{總論:"老者用求。春殘再開。欲求名利。晚遇橫財。",聖意:"家宅　欠利。自身　謹慎。求財　著力。交易　平。婚姻　遲。六甲　女。行人　阻。田蠶　好。六畜　好。尋人　難。公訟　反覆。移徙　更新。失物　凶病。疾病　延滯。山墳　宜改。"},actionAdvice:["春殘花終再開，凡事主後改變，名利晚遇橫財，耐心等待。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:86,displayNo:"第86籤",level:"上籤",title:"觀音第86籤",poem:["春來花發映陽臺","萬里舟行進寶來","躍過禹門三級浪","恰如平地一聲雷"],story:"觀音第86首",classicMeaning:"朝帝受職。如貧得寶。謀望從心。卦中第一。",plainMeaning:"此卦上朝見帝之象。凡事太吉大利也。",categoryReadings:{總論:"朝帝受職。如貧得寶。謀望從心。卦中第一。",聖意:"家宅　有喜。自身　吉。求財　有。交易　春吉。婚姻　成。六甲　順意。行人　喜訊。田蠶　利。六畜　旺。尋人　回。公訟　勝。移徙　可。失物　在。疾病　安。山墳　吉。"},actionAdvice:["上朝見帝如貧得寶，謀望從心，凡事太吉大利，積極把握。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:87,displayNo:"第87籤",level:"上籤",title:"觀音第87籤",poem:["人行半嶺日啣山","峻險巉巖未可攀","仰望上天垂護佑","此身猶在太虛間"],story:"觀音第87首",classicMeaning:"鑿石見玉。淘沙見金。須要著力。只是勞心。",plainMeaning:"此卦淘沙見金之象。凡事有貴人之兆也。",categoryReadings:{總論:"鑿石見玉。淘沙見金。須要著力。只是勞心。",聖意:"家宅　祈福。自身　欠利。求財　勞心。交易　謹慎。婚姻　有阻。六甲　虛。行人　遲。田蠶　平穩。六畜　平穩。尋人　未遇。公訟　虧。移徙　守。失物　凶。疾病　阻。山墳　不阻。"},actionAdvice:["鑿石見玉淘沙見金，凡事須要著力勞心，有貴人之兆。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:88,displayNo:"第88籤",level:"上籤",title:"觀音第88籤",poem:["木雕一虎在山林","遠望威容意不禁","縱說不妨終可謂","此身如入大江心"],story:"觀音第88首",classicMeaning:"爐頭點雪。似耳邊風。可宜作福。後吉前凶。",plainMeaning:"此卦林木虎有威之象。凡事虛驚少實也。",categoryReadings:{總論:"爐頭點雪。似耳邊風。可宜作福。後吉前凶。",聖意:"家宅　不安。自身　口舌。求財　小人。交易　不利。婚姻　不合。六甲　虛險。行人　阻。田蠶　損。六畜　損。尋人　杳。公訟　虧。移徙　守舊。失物　凶。疾病　祭虎。山墳　凶。"},actionAdvice:["木雕之虎似有威實虛，凡事虛驚少實，宜作福祈保，謹慎為上。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:89,displayNo:"第89籤",level:"上籤",title:"觀音第89籤",poem:["出入營謀大吉昌","無瑕玉在石中藏","如今幸得高人指","獲寶從心喜不常"],story:"觀音第89首",classicMeaning:"如石藏玉。貴人指示得祗稱心。歡懷得意。",plainMeaning:"此卦石藏珍寶之象。凡事稱心大吉也。",categoryReadings:{總論:"如石藏玉。貴人指示得祗稱心。歡懷得意。",聖意:"家宅　吉利。自身　康泰。求財　遂。交易　成。婚姻　成就。六甲　生男。行人　動。田蠶　著力。六畜　勤理。尋人　見。公訟　勝。移徙　吉。失物　在。疾病　安。山墳　吉。"},actionAdvice:["如石藏玉遇貴人指示，凡事稱心大吉，積極營謀必有好結果。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:90,displayNo:"第90籤",level:"上籤",title:"觀音第90籤",poem:["忽朝一信天下墀","寶貝船裝滿載歸","若問前程成底事","始終應得貴人提"],story:"觀音第90首",classicMeaning:"若問功名。前有貴人。更添喜氣。財祿豐盈。",plainMeaning:"此卦功名成就之象。凡事宜進大吉也。",categoryReadings:{總論:"若問功名。前有貴人。更添喜氣。財祿豐盈。",聖意:"家宅　若前。自身　吉隨。求財　佳順。交易　諸求。婚姻　事之。六甲　添孫。行人　財更。田蠶　功貴。六畜　問有。尋人　名人。公訟　盈氣。移徙　失物　疾病　山墳　豐喜。"},actionAdvice:["功名成就在望，前有貴人相助，財祿豐盈，凡事宜進大吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:91,displayNo:"第91籤",level:"上籤",title:"觀音第91籤",poem:["好把愁眉須展開","大才大用薦將來","一條大路平如掌","凡有施為總稱懷"],story:"觀音第91首",classicMeaning:"一條大路。可向前行。心中用事。只可向前。",plainMeaning:"此卦前途顯達之象。凡事通泰大吉也。",categoryReadings:{總論:"一條大路。可向前行。心中用事。只可向前。",聖意:"家宅　心只。自身　路行。求財　大前。交易　一可。婚姻　條向。六甲　事順。行人　諸順。田蠶　用向。六畜　中可。尋人　事前。公訟　意昌。移徙　失物　疾病　山墳　如吉。"},actionAdvice:["一條大路平如掌，心中用事只可向前，凡事通泰大吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:92,displayNo:"第92籤",level:"上籤",title:"觀音第92籤",poem:["經商得利稱心懷","福祿榮華倍獲財","若問進身謀望事","秀才一舉狀元回"],story:"觀音第92首",classicMeaning:"自小至大。無阻無礙。作意營謀。功名順遂。",plainMeaning:"此卦自小為商之象。凡事勤儉無憂也。",categoryReadings:{總論:"自小至大。無阻無礙。作意營謀。功名順遂。",聖意:"家宅　安。自身　泰。求財　順遂。交易　勝。婚姻　合。六甲　生男。行人　動。田蠶　半收。六畜　旺。尋人　見。公訟　勝。移徙　如意。失物　在。疾病　即安。山墳　大吉。"},actionAdvice:["自小至大無阻無礙，功名順遂，凡事勤儉無憂，積極進取。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:93,displayNo:"第93籤",level:"上籤",title:"觀音第93籤",poem:["鸞鳳翎毛雨壓垂","此時應被雀輕欺","忽朝一日雲霄霽","依舊還教振羽衣"],story:"觀音第93首",classicMeaning:"小人日盛。君子莫為。只宜守己。待時施為。",plainMeaning:"此卦鸞鳳被雨之象。凡事待時大利也。",categoryReadings:{總論:"小人日盛。君子莫為。只宜守己。待時施為。",聖意:"家宅　欠利。自身　謹防。求財　阻。交易　待時。婚姻　遲滯。六甲　有虛。行人　留連。田蠶　晚。六畜　損。尋人　難。公訟　虧。移徙　守舊。失物　凶。疾病　延。山墳　改。"},actionAdvice:["小人日盛暫時被壓制，只宜守己待時施為，凡事待時大利。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:94,displayNo:"第94籤",level:"上籤",title:"觀音第94籤",poem:["小人君子別賢愚","事有差訛合是非","琴遇知音當鼓操","爭如定靜得便宜"],story:"觀音第94首",classicMeaning:"知音方許。閑事莫理。待得貴人。無不歡喜。",plainMeaning:"此卦要逢知己之象。凡事守常則吉也。",categoryReadings:{總論:"知音方許。閑事莫理。待得貴人。無不歡喜。",聖意:"家宅　慎出。自身　小人。求財　待時。交易　謹慎。婚姻　宜遲。六甲　女。行人　動。田蠶　少。六畜　損。尋人　勤。公訟　和。移徙　失物　速尋。疾病　阻隔。山墳　不利。"},actionAdvice:["知音方許閑事莫理，待得貴人無不歡喜，凡事守常則吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:95,displayNo:"第95籤",level:"上籤",title:"觀音第95籤",poem:["事業功勳暮與朝","榮華物態不勝饒","報君記取金雞鬪","福祿聲名價自超"],story:"觀音第95首",classicMeaning:"志氣心動。守己未遲。金雞報諾。無不歡喜。",plainMeaning:"此卦志氣功名之象。凡事守常大吉也。",categoryReadings:{總論:"志氣心動。守己未遲。金雞報諾。無不歡喜。",聖意:"家宅　祈保。自身　中平。求財　勞心。交易　早斷。婚姻　有成。六甲　安。行人　田蠶　晚成。六畜　成。尋人　難。公訟　急斷。移徙　守。失物　遠。疾病　延纏。山墳　吉。"},actionAdvice:["志氣心動守己未遲，金雞報諾無不歡喜，凡事守常大吉。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:96,displayNo:"第96籤",level:"上籤",title:"觀音第96籤",poem:["巍巍寶塔不尋常","八面玲瓏盡放光","勸汝志心勤頂禮","天龍擁護降千祥"],story:"觀音第96首",classicMeaning:"這些福份。眾人皆有。不用心忙。福德前定。",plainMeaning:"此卦福德現身之象。凡事大吉利也。",categoryReadings:{總論:"這些福份。眾人皆有。不用心忙。福德前定。",聖意:"家宅　許願。自身　許經。求財　正勝。交易　大吉。婚姻　好合。六甲　喜。行人　動。田蠶　平穩。六畜　欠利。尋人　遇。公訟　和。移徙　吉。失物　疾病　禳星。山墳　平。"},actionAdvice:["福德前定不用心忙，眾人皆有此福份，凡事大吉利，虔誠禮佛。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:97,displayNo:"第97籤",level:"上籤",title:"觀音第97籤",poem:["園林月色搖疎影","恍若鋪成滿地瓊","幾度兒童來收拾","豈知收拾總無成"],story:"觀音第97首",classicMeaning:"富貴在天。貧窮是命。不用求謀。皆是前定。",plainMeaning:"此卦當風點燭之象。凡事虛名不利也。",categoryReadings:{總論:"富貴在天。貧窮是命。不用求謀。皆是前定。",聖意:"家宅　祈福。自身　謹慎。求財　得利。交易　慎重。婚姻　中平。六甲　有驚。行人　杳。田蠶　損。六畜　損。尋人　無蹤。公訟　虧。移徙　守舊。失物　凶。疾病　犯陰。山墳　改。"},actionAdvice:["富貴在天不用強求，凡事虛名不利，守舊為宜，謹慎理財。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:98,displayNo:"第98籤",level:"上籤",title:"觀音第98籤",poem:["經商出入事遲疑","恐惹閒愁與是非","如鳥飛投羅網陷","相看能有幾人知"],story:"觀音第98首",classicMeaning:"守舊隨時。待貴人至。若問諸般。主事定遲。",plainMeaning:"此卦守舊隨緣之象。凡事不如意主凶也。",categoryReadings:{總論:"守舊隨時。待貴人至。若問諸般。主事定遲。",聖意:"家宅　憂疑。自身　小人。求財　破。交易　損失。婚姻　不長。六甲　刑損。行人　困。田蠶　損。六畜　損。尋人　杳。公訟　虧。移徙　勿動。失物　凶。疾病　犯羅網。山墳　絕。"},actionAdvice:["守舊隨時待貴人至，凡事不如意主凶，宜守不宜動，謹防小人。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:99,displayNo:"第99籤",level:"上籤",title:"觀音第99籤",poem:["等閑騎馬着鞭來","半有憂危半有財","似火方燒頭上屋","天教一雨蕩殃災"],story:"觀音第99首",classicMeaning:"終身勞力。莫管是非。枷鎖臨時。怨尤自至。",plainMeaning:"此卦半憂半喜之象。凡事只宜行善也。",categoryReadings:{總論:"終身勞力。莫管是非。枷鎖臨時。怨尤自至。",聖意:"家宅　祈保。自身　守慎。求財　破。交易　阻。婚姻　刑剋。六甲　險。行人　困。田蠶　損。六畜　損。尋人　招非。公訟　虧。移徙　守舊。失物　凶。疾病　憂危。山墳　敗。"},actionAdvice:["半憂半喜，凡事只宜行善，莫管是非，守慎為上，行善可化解災厄。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}},
{no:100,displayNo:"第100籤",level:"上籤",title:"觀音第100籤",poem:["欲就東兮欲就西","逢人說事轉痴迷","登山不見神仙面","莫若歸休更勿提"],story:"觀音第100首",classicMeaning:"完滿靈籤。盡報君加。信舊勿動。待等時至。",plainMeaning:"此卦守常勿動之象。凡事宜待時吉也。",categoryReadings:{總論:"完滿靈籤。盡報君加。信舊勿動。待等時至。",聖意:"此是滿籤，諸事不利，大作福力，可保平安。"},actionAdvice:["完滿靈籤諸事不利，大作福力可保平安，信舊勿動待時至。"],warnings:["占卜結果僅供參考"],sourceIds:["fortune_poems_blog"],dataQuality:{poemChecked:true,meaningRewritten:false,traditionalChineseChecked:true}}
];

